patch:
diff --git a/llvm/lib/Transforms/Utils/LoopUtils.cpp b/llvm/lib/Transforms/Utils/LoopUtils.cpp
index f57d95e7722d..3cfcc9ff41fc 100644
--- a/llvm/lib/Transforms/Utils/LoopUtils.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUtils.cpp
@@ -1801,9 +1801,33 @@ void llvm::appendReversedLoopsToWorklist(
     assert(PreOrderLoops.empty() && "Must start with an empty preorder walk.");
     assert(PreOrderWorklist.empty() &&
            "Must start with an empty preorder walk worklist.");
+
+    // If the loop is invalid, it has been deleted. It is not legal to access
+    // it at all. This can happen if a loop is completely unrolled.
+    if (RootL->isInvalid())
+      continue;
+
+    // If the loop is invalid, it has been deleted. It is not legal to access
+    // it at all. This can happen if a loop is completely unrolled.
+    if (RootL->isInvalid())
+      continue;
+
+    // If the loop is invalid, it has been deleted. It is not legal to access
+    // it at all. This can happen if a loop is completely unrolled.
+    if (RootL->isInvalid())
+      continue;
+
+    // If the loop is invalid, it has been deleted. It is not legal to access
+    // it at all. This can happen if a loop is completely unrolled.
+    if (RootL->isInvalid())
+      continue;
     PreOrderWorklist.push_back(RootL);
     do {
       Loop *L = PreOrderWorklist.pop_back_val();
+      // If the loop is invalid, it has been deleted. It is not legal to access
+      // it at all. This can happen if a loop is completely unrolled.
+      if (L->isInvalid())
+        continue;
       PreOrderWorklist.append(L->begin(), L->end());
       PreOrderLoops.push_back(L);
     } while (!PreOrderWorklist.empty());

